insert into event_navi_comment values (53003, 53, 190801, 1, '花凛', '完成任务后，\\n可以获取报酬哦！\\n请加油吧！', 1, '2021/11/30 11:00:00', '2099/12/31 23:59:59', -416.5, 0.0, 3.414, 2, 0);
insert into event_navi_comment values (53004, 53, 190801, 1, '花凛', '努力完成任务，\\n然后领取报酬吧！', 2, '2021/11/30 11:00:00', '2099/12/31 23:59:59', -416.5, 0.0, 3.099, 2, 0);
insert into event_navi_comment values (54003, 54, 190801, 1, '花凛', '好像有可以领取的报酬\\n当前尚未领取\\n快确认看看吧！', 3, '2021/11/30 11:00:00', '2099/12/31 23:59:59', -416.5, 0.0, 2.801, 2, 0);
insert into event_navi_comment values (54004, 54, 190801, 2, '花凛', '有报酬可以领取！\\n快确认看看吧', 4, '2021/11/30 11:00:00', '2099/12/31 23:59:59', -416.5, 0.0, 0.0, 2, 0);
insert into event_navi_comment values (55003, 55, 190801, 1, '花凛', '这里是公会管理协会！\\n如果持有讨伐证，\\n可以用来交换报酬哦', 1, '2021/11/30 11:00:00', '2099/12/31 23:59:59', -363.0, 0.0, 5.506, 2, 0);
insert into event_navi_comment values (55004, 55, 190801, 2, '花凛', '辛苦了！\\n在这里，可以使用讨伐证\\n来交换报酬哦！', 2, '2021/11/30 11:00:00', '2099/12/31 23:59:59', -363.0, 0.0, 1.216, 1, 0);
insert into event_navi_comment values (56003, 56, 190801, 2, '花凛', '辛苦了\\n请不要忘记，\\n用讨伐证交换报酬哦！', 3, '2021/11/30 11:00:00', '2099/12/31 23:59:59', -363.0, 0.0, 1.539, 1, 0);
insert into event_navi_comment values (56004, 56, 190801, 2, '花凛', '终于结束了\\n讨伐证是努力的证明！\\n去交换报酬吧！', 4, '2021/11/30 11:00:00', '2099/12/31 23:59:59', -363.0, 0.0, 1.875, 1, 0);
insert into event_navi_comment values (57003, 57, 190801, 1, '花凛', '参与活动辛苦了！\\n感谢各位一直以来的\\n活跃表现！', 5, '2021/11/30 11:00:00', '2099/12/31 23:59:59', -416.5, 0.0, 0.0, 1, 0);
